app = Flask(__name__)

# Mock database
PRODUCTS = [
    {"id": 1, "name": "Laptop", "price": 999.99, "category_id": 1, "description": "High-performance laptop"},
    {"id": 2, "name": "Mouse", "price": 29.99, "category_id": 1, "description": "Wireless mouse"},
    {"id": 3, "name": "Keyboard", "price": 79.99, "category_id": 1, "description": "Mechanical keyboard"},
]

CATEGORIES = [
    {"id": 1, "name": "Electronics", "description": "Electronic devices"},
    {"id": 2, "name": "Clothing", "description": "Apparel and accessories"},
]

REVIEWS = [
    {"id": 1, "product_id": 1, "user_name": "John", "rating": 5, "comment": "Great product!"},
    {"id": 2, "product_id": 1, "user_name": "Jane", "rating": 4, "comment": "Good value"},
    {"id": 3, "product_id": 2, "user_name": "Bob", "rating": 3, "comment": "Average"},
]

# Security configurations
MAX_QUERY_DEPTH = 5
MAX_QUERY_COMPLEXITY = 100
MAX_ALIASES = 5
RATE_LIMIT_REQUESTS = 100
RATE_LIMIT_WINDOW = 60

# Rate limiting storage
rate_limit_storage = defaultdict(list)

# Query complexity costs
COMPLEXITY_COSTS = {
    'products': 10,
    'product': 5,
    'categories': 5,
    'category': 3,
    'reviews': 8,
    'review': 4,
}


def calculate_query_depth(node, depth=0):
    if not hasattr(node, 'selection_set') or not node.selection_set:
        return depth
    
    max_depth = depth
    for selection in node.selection_set.selections:
        current_depth = calculate_query_depth(selection, depth + 1)
        max_depth = max(max_depth, current_depth)
    
    return max_depth


def calculate_query_complexity(node, complexity=0):
    if not hasattr(node, 'selection_set') or not node.selection_set:
        return complexity
    
    total_complexity = complexity
    for selection in node.selection_set.selections:
        field_name = selection.name.value if hasattr(selection, 'name') else None
        if field_name in COMPLEXITY_COSTS:
            total_complexity += COMPLEXITY_COSTS[field_name]
        total_complexity += calculate_query_complexity(selection, 0)
    
    return total_complexity


def count_aliases(node, aliases=None):
    if aliases is None:
        aliases = set()
    
    if not hasattr(node, 'selection_set') or not node.selection_set:
        return len(aliases)
    
    for selection in node.selection_set.selections:
        if hasattr(selection, 'alias') and selection.alias:
            aliases.add(selection.alias.value)
        count_aliases(selection, aliases)
    
    return len(aliases)


def check_rate_limit(client_id):
    current_time = time.time()
    rate_limit_storage[client_id] = [
        timestamp for timestamp in rate_limit_storage[client_id]
        if current_time - timestamp < RATE_LIMIT_WINDOW
    ]
    
    if len(rate_limit_storage[client_id]) >= RATE_LIMIT_REQUESTS:
        return False
    
    rate_limit_storage[client_id].append(current_time)
    return True


def validate_query_security(document):
    for definition in document.definitions:
        if hasattr(definition, 'selection_set'):
            depth = calculate_query_depth(definition)
            if depth > MAX_QUERY_DEPTH:
                raise Exception(f"Query depth {depth} exceeds maximum allowed depth of {MAX_QUERY_DEPTH}")
            
            complexity = calculate_query_complexity(definition)
            if complexity > MAX_QUERY_COMPLEXITY:
                raise Exception(f"Query complexity {complexity} exceeds maximum allowed complexity of {MAX_QUERY_COMPLEXITY}")
            
            alias_count = count_aliases(definition)
            if alias_count > MAX_ALIASES:
                raise Exception(f"Number of aliases {alias_count} exceeds maximum allowed of {MAX_ALIASES}")


class ReviewType(ObjectType):
    id = Int()
    product_id = Int()
    user_name = String()
    rating = Int()
    comment = String()


class ProductType(ObjectType):
    id = Int()
    name = String()
    price = Float()
    category_id = Int()
    description = String()
    reviews = List(ReviewType)
    
    def resolve_reviews(self, info):
        return [r for r in REVIEWS if r['product_id'] == self.id]


class CategoryType(ObjectType):
    id = Int()
    name = String()
    description = String()
    products = List(ProductType)
    
    def resolve_products(self, info):
        return [ProductType(**p) for p in PRODUCTS if p['category_id'] == self.id]


class Query(ObjectType):
    products = List(ProductType, limit=Int(default_value=10))
    product = Field(ProductType, id=Int(required=True))
    categories = List(CategoryType)
    category = Field(CategoryType, id=Int(required=True))
    reviews = List(ReviewType, product_id=Int())
    review = Field(ReviewType, id=Int(required=True))
    
    def resolve_products(self, info, limit=10):
        if limit > 50:
            raise Exception("Limit cannot exceed 50")
        return [ProductType(**p) for p in PRODUCTS[:limit]]
    
    def resolve_product(self, info, id):
        product = next((p for p in PRODUCTS if p['id'] == id), None)
        if product:
            return ProductType(**product)
        return None
    
    def resolve_categories(self, info):
        return [CategoryType(**c) for c in CATEGORIES]
    
    def resolve_category(self, info, id):
        category = next((c for c in CATEGORIES if c['id'] == id), None)
        if category:
            return CategoryType(**category)
        return None
    
    def resolve_reviews(self, info, product_id=None):
        if product_id:
            return [ReviewType(**r) for r in REVIEWS if r['product_id'] == product_id]
        return [ReviewType(**r) for r in REVIEWS]
    
    def resolve_review(self, info, id):
        review = next((r for r in REVIEWS if r['id'] == id), None)
        if review:
            return ReviewType(**review)
        return None


class AddReview(Mutation):
    class Arguments:
        product_id = Int(required=True)
        user_name = String(required=True)
        rating = Int(required=True)
        comment = String(required=True)
    
    review = Field(ReviewType)
    
    def mutate(self, info, product_id, user_name, rating, comment):
        if rating < 1 or rating > 5:
            raise Exception("Rating must be between 1 and 5")
        
        if len(comment) > 500:
            raise Exception("Comment cannot exceed 500 characters")
        
        new_review = {
            "id": len(REVIEWS) + 1,
            "product_id": product_id,
            "user_name": user_name,
            "rating": rating,
            "comment": comment
        }
        REVIEWS.append(new_review)
        return AddReview(review=ReviewType(**new_review))


class Mutations(ObjectType):
    add_review = AddReview.Field()


schema = Schema(query=Query, mutation=Mutations)


class SecureGraphQLView(GraphQLView):
    def dispatch_request(self):
        try:
            client_id = request.remote_addr
            
            if not check_rate_limit(client_id):
                return jsonify({
                    'errors': [{'message': 'Rate limit exceeded. Please try again later.'}]
                }), 429
            
            data = self.parse_body()
            query = data.get('query', '')
            
            if query.strip().startswith('mutation'):
                pass
            else:
                from graphql import parse
                try:
                    document = parse(query)
                    validate_query_security(document)
                except Exception as e:
                    return jsonify({
                        'errors': [{'message': str(e)}]
                    }), 400
            
            batch_queries = query.count('{')
            if batch_queries > 5:
                return jsonify({
                    'errors': [{'message': 'Batch query limit exceeded'}]
                }), 400
            
            if '__schema' in query or '__type' in query:
                if request.headers.get('X-Allow-Introspection') != 'true':
                    return jsonify({
                        'errors': [{'message': 'Introspection is disabled in production'}]
                    }), 403
            
            return super().dispatch_request()
            
        except Exception as e:
            return jsonify({
                'errors': [{'message': 'An error occurred processing your request'}]
            }), 500


